def run_ops(capacity, ops):
    from collections import OrderedDict
    cache = OrderedDict()
    results = []
    for op in ops:
        if op[0] == "put":
            key, val = op[1], op[2]
            if key in cache:
                cache.move_to_end(key)
            cache[key] = val
            if len(cache) > capacity:
                cache.popitem(last=False)
        elif op[0] == "get":
            key = op[1]
            if key in cache:
                cache.move_to_end(key)
                results.append(cache[key])
            else:
                results.append(-1)
    return results

