    for row in matrix:
        for i in range(n):
            heights[i] = heights[i] + 1 if row[i] == 1 else 0
        stack = [-1]
        for i in range(n + 1):
            while stack[-1] != -1 and heights[stack[-1]] >= heights[i]:
                h = heights[stack.pop()]
                w = i - stack[-1] - 1
                best = max(best, h * w)
            stack.append(i)
    return best

def burst_balloons(nums):
    vals = [1] + nums + [1]
    n = len(vals)
    dp = [[0] * n for _ in range(n)]
    for length in range(2, n):
        for left in range(0, n - length):
            right = left + length
            best = 0
            for k in range(left + 1, right):
                cur = vals[left] * vals[k] * vals[right] + dp[left][k] + dp[k][right]
                if cur > best:
                    best = cur
            dp[left][right] = best
    return dp[0][n - 1]

def decode_string(s):
    num_stack = []
    str_stack = []
    cur = ""
    num = 0
    for ch in s:
        if ch.isdigit():
            num = num * 10 + int(ch)
        elif ch == '[':
            num_stack.append(num)
            str_stack.append(cur)
            num = 0
            cur = ""
        elif ch == ']':
            k = num_stack.pop()
            prev = str_stack.pop()
            cur = prev + cur * k
        else:
            cur += ch
    return cur

def longest_consecutive(nums):
    s = set(nums)
    best = 0
    for x in s:
        if x - 1 not in s:
            length = 1
            cur = x
            while cur + 1 in s:
                cur += 1
                length += 1
            best = max(best, length)
    return best

def find_order(num_courses, prerequisites):
    import heapq
    adj = [[] for _ in range(num_courses)]
    indeg = [0] * num_courses
    for a, b in prerequisites:
        adj[b].append(a)
        indeg[a] += 1
    heap = [i for i in range(num_courses) if indeg[i] == 0]
    heapq.heapify(heap)
    order = []
    while heap:
        node = heapq.heappop(heap)
        order.append(node)
        for nxt in adj[node]:
            indeg[nxt] -= 1
            if indeg[nxt] == 0:
                heapq.heappush(heap, nxt)
    if len(order) != num_courses:
        return []
    return order

def run_ops(ops, args):
    import heapq
    small = []
    large = []
    out = []
    for op, arg in zip(ops, args):
        if op == "addNum":
            x = arg
            heapq.heappush(small, -x)
            heapq.heappush(large, -heapq.heappop(small))
            if len(large) > len(small):
                heapq.heappush(small, -heapq.heappop(large))
            out.append(None)
        elif op == "findMedian":
            if len(small) > len(large):
                out.append(float(-small[0]))
            else:
                out.append((-small[0] + large[0]) / 2.0)
    return out

def max_envelopes(envelopes):
    import bisect
    envelopes.sort(key=lambda e: (e[0], -e[1]))
    tails = []
    for _, h in envelopes:
        idx = bisect.bisect_left(tails, h)
        if idx == len(tails):
            tails.append(h)
        else:
            tails[idx] = h
    return len(tails)

def min_cut(s):
    n = len(s)
    if n == 0:
        return 0
    pal = [[False] * n for _ in range(n)]
    cuts = [0] * n
    for i in range(n):
        min_c = i
        for j in range(i + 1):
            if s[j] == s[i] and (i - j < 2 or pal[j + 1][i - 1]):
                pal[j][i] = True
                min_c = 0 if j == 0 else min(min_c, cuts[j - 1] + 1)
        cuts[i] = min_c
    return cuts[n - 1]

def num_distinct(s, t):
    m, n = len(s), len(t)
    dp = [0] * (n + 1)
    dp[0] = 1
    for i in range(1, m + 1):
        for j in range(n, 0, -1):
            if s[i - 1] == t[j - 1]:
                dp[j] += dp[j - 1]
    return dp[n]

def is_interleave(s1, s2, s3):
    m, n = len(s1), len(s2)
    if m + n != len(s3):
        return False
    dp = [[False] * (n + 1) for _ in range(m + 1)]
    dp[0][0] = True
    for i in range(m + 1):
        for j in range(n + 1):
            if i > 0 and s1[i - 1] == s3[i + j - 1] and dp[i - 1][j]:
                dp[i][j] = True
            if j > 0 and s2[j - 1] == s3[i + j - 1] and dp[i][j - 1]:
                dp[i][j] = True
    return dp[m][n]

def is_scramble(s1, s2):
    from functools import lru_cache
    if len(s1) != len(s2):
        return False
    @lru_cache(maxsize=None)
    def solve(a, b):
        if a == b:
            return True
        if sorted(a) != sorted(b):
            return False
        n = len(a)
        for i in range(1, n):
            if solve(a[:i], b[:i]) and solve(a[i:], b[i:]):
                return True
            if solve(a[:i], b[n - i:]) and solve(a[i:], b[:n - i]):
                return True
        return False
    return solve(s1, s2)

def longest_increasing_path(matrix):
    if not matrix or not matrix[0]:
        return 0
    m, n = len(matrix), len(matrix[0])
    memo = [[0] * n for _ in range(m)]
    def dfs(i, j):
        if memo[i][j]:
            return memo[i][j]
        best = 1
        for di, dj in ((1, 0), (-1, 0), (0, 1), (0, -1)):
            ni, nj = i + di, j + dj
            if 0 <= ni < m and 0 <= nj < n and matrix[ni][nj] > matrix[i][j]:
                best = max(best, 1 + dfs(ni, nj))
        memo[i][j] = best
        return best
    return max(dfs(i, j) for i in range(m) for j in range(n))

def split_array(nums, k):
    def can(limit):
        count = 1
        cur = 0
        for x in nums:
            if cur + x > limit:
                count += 1
                cur = x
                if count > k:
                    return False
            else:
                cur += x
        return True
    lo, hi = max(nums), sum(nums)
    while lo < hi:
        mid = (lo + hi) // 2
        if can(mid):
            hi = mid
        else:
            lo = mid + 1
    return lo
